// يجهّز نص المرشح لإرساله إلى Claude
const b = $json.body || {};
const story = (b.story || "").toString().trim();
return [{ json: { story: story || "لا يوجد نص" } }];

// يجهّز حقول صفحة Notion من مخرجات Claude + بيانات النموذج
let parsed = {};
try {
  let txt = "{}";
  if ($json.content && $json.content[0] && $json.content[0].text) txt = $json.content[0].text;
  else if (typeof $json.text === "string") txt = $json.text;
  else if (typeof $json.output === "string") txt = $json.output;
  parsed = JSON.parse(txt.replace(/```json|```/g, "").trim());
} catch (e) { parsed = {}; }

const b = $('استقبال النموذج').item.json.body || {};
const s = (v) => (v || "").toString().slice(0, 1900);

const lines = [];
function sec(t, v){ if (v) { lines.push(t + ":"); lines.push(v.toString()); lines.push(""); } }
sec("الملخص المهني", parsed.summary);
sec("المهارات", Array.isArray(parsed.skills) ? parsed.skills.join(" · ") : parsed.skills);
sec("أبرز الإنجازات", Array.isArray(parsed.achievements) ? parsed.achievements.map(a => "• " + a).join("\n") : parsed.achievements);
if (Array.isArray(parsed.experience) && parsed.experience.length) {
  const ex = parsed.experience.map(e => {
    const head = [e.title, e.org, e.period].filter(Boolean).join(" — ");
    const pts = (e.points || []).map(p => "• " + p).join("\n");
    return pts ? head + "\n" + pts : head;
  }).join("\n\n");
  sec("الخبرات", ex);
}
sec("التعليم", parsed.education);
sec("اللغات", Array.isArray(parsed.languages) ? parsed.languages.join("، ") : parsed.languages);

const body = lines.join("\n");
const chunk = (i) => body.slice(i * 1900, (i + 1) * 1900);

return [{ json: {
  name: s(b.name || parsed.name || "بدون اسم"),
  email: s(b.email || parsed.email) || null,
  phone: s(b.phone || parsed.phone) || null,
  cities: s(b.cities || parsed.cities),
  titles: s(Array.isArray(parsed.target_titles) ? parsed.target_titles.join(" · ") : parsed.target_titles),
  salary: s(b.salary || parsed.salary),
  keywords: s(Array.isArray(parsed.skills) ? parsed.skills.join(", ") : parsed.skills),
  linkedin: s(b.linkedin),
  consent: b.consent === true,
  today: new Date().toISOString().slice(0, 10),
  chunk1: chunk(0), chunk2: chunk(1), chunk3: chunk(2), chunk4: chunk(3)
}}];
